                    datalabels: {
                        display: (context: any) => {
                            const val = Number(context.dataset.data[context.dataIndex]);
                            return !isNaN(val) && val > 0;
                        },
                        color: '#fff',
                        font: { size: 9, weight: 'bold' },
                        formatter: (value: number) => {
                            if (barChartMode === 'value') return formatCurrencyCompact(value);
                            return value;
                        }
