                    tooltip: {
                        callbacks: {
                            label: function (context: any) {
                                let label = context.dataset.label || '';
                                if (label) label += ': ';
                                if (context.parsed.y !== null) {
                                    if (barChartMode === 'value') label += formatCurrency(context.parsed.y);
                                    else label += context.parsed.y;
                                }
                                return label;
                            }
                        }
                    }
