            },
            options: {
                indexAxis: 'y',
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: { display: false },
                    tooltip: { filter: (tooltipItem: any) => tooltipItem.datasetIndex === 1 }
                },
                scales: {
                    x: { stacked: true, display: false },
                    y: {
